SELECT 
FROM bluenote_notification.notification_record
WHERE receiver_id = #{receiverId}
  AND source_type = #{sourceType}
  AND source_id = #{sourceId}
  AND notification_type = #{notificationType}
ORDER BY created_at DESC, notification_id DESC
LIMIT 1

SELECT 
FROM bluenote_notification.notification_record
WHERE receiver_id = #{receiverId}
  AND visible_status = 1

  AND category = #{category}


  AND (
    last_event_at < #{cursorLastEventAt}
    OR (last_event_at = #{cursorLastEventAt} AND notification_id < #{cursorNotificationId})
  )

ORDER BY last_event_at DESC, notification_id DESC
LIMIT #{size}

